SELECT content_id, COUNT(*) AS view_count
FROM content_views
GROUP BY content_id;

SELECT content_id, view_count AS total_views
FROM content
ORDER BY view_count DESC;

SELECT view_count
FROM content
WHERE content_id = 'specific_content_id';

SELECT content_id, GROUP_CONCAT(tag_id) AS tags
FROM content_tags
GROUP BY content_id;
